/**
 * Spiderweb Mesh Network — Orb Web Topology as Mesh Architecture
 *
 * Maps the spiderweb topology (β₁ = k·s) directly to mesh networking:
 *   - Radials (k) = peer connections / streams
 *   - Spiral rings (s) = relay hop depth / pipeline stages
 *   - Hub = coordinator / gateway node
 *   - β₁ = k·s = independent routing paths
 *   - Δβ = routing deficit in Bules
 *
 * Gnostic mesh configurations prescribe architectures at each scale,
 * from Bythos (isolated node) through Pleroma (55-path full mesh).
 *
 * @see ../lean/Lean/ForkRaceFoldTheorems/SpiderwebMeshNetwork.lean for formal proofs
 * @packageDocumentation
 */

// ─── Types ──────────────────────────────────────────────────────────

export interface MeshConfig {
  /** Number of direct peer connections (radials) */
  readonly peers: number;
  /** Relay hop depth (spiral rings) */
  readonly hops: number;
}

export type GnosticMeshLevel =
  | 'bythos'
  | 'barbelo'
  | 'syzygy'
  | 'proton'
  | 'primitives'
  | 'emanations'
  | 'sophia'
  | 'kenoma'
  | 'void'
  | 'pleroma';

export type MeshRegime = 'laminar' | 'transitional' | 'turbulent';

export interface MeshTopologyReport {
  readonly config: MeshConfig;
  readonly level: GnosticMeshLevel | null;
  readonly routingPaths: number;
  readonly wireCount: number;
  readonly nodeCount: number;
  readonly regime: MeshRegime;
  readonly reynoldsEstimate: number;
  readonly peerFailureCost: number;
  readonly relayFailureCost: number;
}

export interface MeshDeficitReport {
  readonly required: number;
  readonly available: number;
  readonly deficit: number;
  readonly utilization: number;
  readonly tcpWaste: number;
  readonly assessment: string;
}

export interface MeshUpgradePath {
  readonly from: GnosticMeshLevel;
  readonly to: GnosticMeshLevel;
  readonly currentPaths: number;
  readonly targetPaths: number;
  readonly deficit: number;
  readonly additionalWires: number;
  readonly additionalNodes: number;
}

/**
 * Projection frame for shape-vs-unit accounting.
 * Mirrors Lean surface: ProjectionParadoxUnits.lean
 */
export interface ProjectionFrame {
  /** Observed chart dimension (post-projection). */
  readonly observedDim: number;
  /** Latent/evolved chart dimension (pre-projection). */
  readonly latentDim: number;
}

/**
 * Minimal witness bundle for projection paradox detection.
 * Mirrors Lean definition of ProjectionParadox witnesses.
 */
export interface ProjectionParadoxWitness {
  /** Whether any observed state appears solved after projection. */
  readonly observedHasSolution: boolean;
  /** Whether a solved latent state exists before projection. */
  readonly latentHasSolution: boolean;
  /** Whether solved/unsolved latent states collapse to one observation. */
  readonly hasCollapsedSplit: boolean;
}

export interface ProjectionShapeUnitReport {
  readonly frame: ProjectionFrame;
  readonly dimensionalUnitGap: number;
  readonly hasDimensionalUnitGap: boolean;
  readonly reducedObservedLatentRatio: readonly [number, number];
  readonly isProjectionParadox: boolean;
  /** Atomic paradox units (OneParadox witnesses). */
  readonly paradoxUnits: number;
  /** Structural shape witness shorthand (units > 0). */
  readonly hasShape: boolean;
}

export interface ParadoxUnitSandwichReport {
  /** Predictive lower bound from frame alone. */
  readonly predictedLowerBound: number;
  /** Observed paradox units from witness evidence. */
  readonly observedUnits: number;
  /** Dimensional upper bound from latent-observed gap. */
  readonly dimensionalUpperBound: number;
  /** Whether lower <= observed <= upper. */
  readonly withinBounds: boolean;
}

export interface ProjectionPredictiveReport {
  readonly frame: ProjectionFrame;
  readonly predictedLowerBound: number;
  readonly observedUnits: number;
  /** observed - predicted */
  readonly residual: number;
  /** Exact predictive hit (residual == 0). */
  readonly consistent: boolean;
}

export interface ReductionProjectionInput {
  readonly id: string;
  readonly frame: ProjectionFrame;
  readonly witness: ProjectionParadoxWitness;
}

export interface ReductionProjectionScanReport {
  readonly id: string;
  readonly shapeUnit: ProjectionShapeUnitReport;
  readonly sandwich: ParadoxUnitSandwichReport;
  readonly predictive: ProjectionPredictiveReport;
}

// ─── Gnostic Mesh Configurations ────────────────────────────────────

